from flask import request, Flask, jsonify
import ldap

app = Flask(__name__)

@app.route("/normal")
def normal():
    dc = request.args.get('dc')
    username = request.args.get('username')
    if not dc or not username:
        return jsonify(error="Missing parameters"), 400

    if '.' not in dc:
        return jsonify(error="Invalid DC format"), 400

    base_dn_parts = ['dc=' + part for part in dc.split('.')]
    base_dn = ','.join(base_dn_parts)

    escaped_username = ldap.filter.escape_filter_string(username)
    filter_str = f'(uid={escaped_username})'

    try:
        ldap_conn = ldap.initialize('ldap://localhost:389')
        ldap_conn.bind()
        result = ldap_conn.search_s(base_dn, ldap.SCOPE_SUBTREE, filter_str)
        return jsonify(result)
    except ldap.LDAPError as e:
        return jsonify(error=str(e)), 500
    finally:
        if 'ldap_conn' in locals():
            ldap_conn.unbind()

